And now let the fun begin! First, let's import the skyline library we installed earlier. We also need to import the  package for converting string values to float64, which is necessary for the skyline calculations:// main.go
import (
  // ...other imports
  "strconv"
  // ...
  "github.com/gkoos/skyline/skyline"
)
\
Note that while we download the module with go get github.com/gkoos/skyline, we import the  subpackage in our code: "github.com/gkoos/skyline/skyline".Now we can implement the skyline calculation. We will create a function  that takes the data and the preferences for each dimension, transforms the data into the appropriate format, and returns the skyline points:// main.go
func computeSkyline(data [][]string, config *Config) ([]skyline.Point, error) {
    // Make sure there's data
    if len(data) <= 1 {
        return nil, fmt.Errorf("not enough data for skyline calculation (need at least 2 rows including header)")
    }

    // Prepare data for skyline calculation (skip header)
    rawData := data[1:]

    // Convert string data to skyline.Point format
    var points []skyline.Point
    for _, row := range rawData {
        // Convert strings to float64
        val1, err1 := strconv.ParseFloat(row[0], 64)
        val2, err2 := strconv.ParseFloat(row[1], 64)
        if err1 != nil || err2 != nil {
            return nil, fmt.Errorf("error parsing numeric values in row: %v", row)
        }
        points = append(points, skyline.Point{val1, val2})
    }

    // Set up preferences from config
    var prefs skyline.Preference
    if config.Dim1Pref == "min" {
        prefs = append(prefs, skyline.Min)
    } else {
        prefs = append(prefs, skyline.Max)
    }
    if config.Dim2Pref == "min" {
        prefs = append(prefs, skyline.Min)
    } else {
        prefs = append(prefs, skyline.Max)
    }

    // Calculate skyline
    return skyline.Skyline(points, nil, prefs, config.Algorithm)
}
\
Let's add this step to the  function as well:func run(config *Config) {
    data, err := readCSV(config.InputFile, config.Dim1, config.Dim2)
    if err != nil {
        color.Red("Error reading CSV: %v\n", err)
        return
    }

    result, err := computeSkyline(data, config)
    if err != nil {
        color.Red("Error calculating skyline: %v\n", err)
        return
    }

    color.Green("Skyline calculation completed!")
    fmt.Printf("Skyline (%s): %v\n", config.Algorithm, result)
}
Finally, we need to write the skyline points to the output CSV file. We will create a function  that takes the skyline points and writes them to a CSV file along with the original data:func writeOutputCSV(filePath string, originalData [][]string, skylinePoints []skyline.Point, config *Config) error {
    file, err := os.Create(filePath)
    if err != nil {
        return fmt.Errorf("error creating file: %v", err)
    }
    defer file.Close()

    writer := csv.NewWriter(file)
    defer writer.Flush()

    // Write header
    header := []string{originalData[0][0], originalData[0][1], "skyline"}
    if err := writer.Write(header); err != nil {
        return fmt.Errorf("error writing header: %v", err)
    }

    // Convert skyline points to a map for quick lookup
    skylineMap := make(map[string]bool)
    for _, point := range skylinePoints {
        key := fmt.Sprintf("%.6f,%.6f", point[0], point[1])
        skylineMap[key] = true
    }

    // Write data rows
    for i := 1; i < len(originalData); i++ {
        row := originalData[i]

        // Parse the values
        val1, err1 := strconv.ParseFloat(row[0], 64)
        val2, err2 := strconv.ParseFloat(row[1], 64)
        if err1 != nil || err2 != nil {
            continue // Skip invalid rows
        }

        key := fmt.Sprintf("%.6f,%.6f", val1, val2)
        isSkyline := "false"
        if skylineMap[key] {
            isSkyline = "true"
        }

        record := []string{row[0], row[1], isSkyline}
        if err := writer.Write(record); err != nil {
            return fmt.Errorf("error writing record: %v", err)
        }
    }

    return nil
}
\
This function creates a new CSV file, writes the header, and then writes each row of the original data along with a new column indicating whether the point is a skyline point or not. We also make sure to skip invalid rows that cannot be parsed as floats.We can now add this step to the  function:func run(config *Config) {
    data, err := readCSV(config.InputFile, config.Dim1, config.Dim2)
    if err != nil {
        color.Red("Error reading CSV: %v\n", err)
        return
    }

    result, err := computeSkyline(data, config)
    if err != nil {
        color.Red("Error calculating skyline: %v\n", err)
        return
    }

    err = writeOutputCSV(config.OutputFile, data, result, config)
    if err != nil {
        color.Red("Error writing output CSV: %v\n", err)
        return
    }

    color.Green("Skyline calculation completed!")
}
\
